"""Lógica principal del experimento federado."""from __future__ import annotationsimport copyfrom dataclasses import dataclassimport pandas as pdfrom federated_skin.config.settings import FederatedExperimentConfigfrom federated_skin.data.splits import df_to_xy, make_train_test_splitfrom federated_skin.federation.aggregation import aggregate_client_statesfrom federated_skin.federation.clients import MobileFleetSimulatorfrom federated_skin.models.global_model import FederatedGlobalModelfrom federated_skin.utils.logging_utils import log_info@dataclassclass FederatedExperimentResult:    """    Resultado final del experimento federado.    """    final_model: FederatedGlobalModel    best_balanced_model: FederatedGlobalModel    best_macro_f1_model: FederatedGlobalModel    history_df: pd.DataFrame    best_balanced_round: int    best_macro_f1_round: int    test_df: pd.DataFrame@dataclassclass FederatedExperiment:    """    Orquestador del experimento federado.    """    df_features: pd.DataFrame    config: FederatedExperimentConfig    logger: object | None = None    def run(self) -> FederatedExperimentResult:        """        Ejecuta el experimento federado completo.        """        df_seed, df_pool, df_test = make_train_test_split(            df=self.df_features,            seed_size=self.config.seed_size,            test_size=self.config.test_size,            random_state=self.config.random_state,        )        log_info(self.logger, "Seed inicial: %d imágenes", len(df_seed))        log_info(self.logger, "Pool móvil: %d imágenes", len(df_pool))        log_info(self.logger, "Test fijo: %d imágenes", len(df_test))        X_seed, y_seed = df_to_xy(df_seed)        X_test, y_test = df_to_xy(df_test)        global_model = FederatedGlobalModel(random_state=self.config.random_state)        global_model.fit_initial(X_seed, y_seed)        baseline = global_model.evaluate(X_test, y_test)        log_info(            self.logger,            "Baseline | acc=%.4f | bal_acc=%.4f | macro_f1=%.4f",            baseline["accuracy"],            baseline["balanced_accuracy"],            baseline["macro_f1"],        )        history_rows = [            {                "round": 0,                "accuracy": baseline["accuracy"],                "balanced_accuracy": baseline["balanced_accuracy"],                "macro_f1": baseline["macro_f1"],                "num_clients": 0,                "num_images": len(df_seed),            }        ]        best_bal_acc = baseline["balanced_accuracy"]        best_macro_f1 = baseline["macro_f1"]        best_balanced_round = 0        best_macro_f1_round = 0        best_state_bal = copy.deepcopy(global_model.get_state())        best_state_f1 = copy.deepcopy(global_model.get_state())        patience_counter = 0        best_early_metric = baseline[self.config.early_stopping_metric]        fleet = MobileFleetSimulator(            df_pool=df_pool,            random_state=self.config.random_state,        )        df_pool_reset = df_pool.reset_index(drop=True)        for round_idx in range(1, self.config.rounds + 1):            clients = fleet.sample_clients_without_replacement(                num_clients=self.config.clients_per_round,                images_per_client=self.config.local_images_per_client,                class_bias=self.config.client_class_bias,            )            client_states = []            total_images_this_round = 0            for client in clients:                client_df = df_pool_reset.iloc[client.row_indices].copy()                if client_df.empty:                    continue                X_client, y_client = df_to_xy(client_df)                total_images_this_round += len(client_df)                client_state = global_model.client_update(                    X_client=X_client,                    y_client_str=y_client,                    local_epochs=self.config.local_epochs,                    noise_std=self.config.privacy_noise_std,                )                client_states.append(client_state)            new_coef, new_intercept = aggregate_client_states(                global_coef=global_model.model.coef_,                global_intercept=global_model.model.intercept_,                client_states=client_states,                server_lr=self.config.server_lr,            )            global_model.model.coef_ = new_coef            global_model.model.intercept_ = new_intercept            metrics = global_model.evaluate(X_test, y_test)            if metrics["balanced_accuracy"] > best_bal_acc:                best_bal_acc = metrics["balanced_accuracy"]                best_balanced_round = round_idx                best_state_bal = copy.deepcopy(global_model.get_state())            if metrics["macro_f1"] > best_macro_f1:                best_macro_f1 = metrics["macro_f1"]                best_macro_f1_round = round_idx                best_state_f1 = copy.deepcopy(global_model.get_state())            monitored_value = metrics[self.config.early_stopping_metric]            if monitored_value > best_early_metric:                best_early_metric = monitored_value                patience_counter = 0            else:                patience_counter += 1            history_rows.append(                {                    "round": round_idx,                    "accuracy": metrics["accuracy"],                    "balanced_accuracy": metrics["balanced_accuracy"],                    "macro_f1": metrics["macro_f1"],                    "num_clients": len(client_states),                    "num_images": total_images_this_round,                }            )            log_info(                self.logger,                "Ronda %02d | clientes=%d | imgs=%d | acc=%.4f | bal_acc=%.4f | macro_f1=%.4f",                round_idx,                len(client_states),                total_images_this_round,                metrics["accuracy"],                metrics["balanced_accuracy"],                metrics["macro_f1"],            )            if patience_counter >= self.config.early_stopping_patience:                log_info(                    self.logger,                    "Early stopping activado en ronda %02d (sin mejora en %s durante %d rondas).",                    round_idx,                    self.config.early_stopping_metric,                    self.config.early_stopping_patience,                )                break        history_df = pd.DataFrame(history_rows)        best_balanced_model = FederatedGlobalModel(random_state=self.config.random_state)        best_balanced_model.set_state(best_state_bal)        best_macro_f1_model = FederatedGlobalModel(random_state=self.config.random_state)        best_macro_f1_model.set_state(best_state_f1)        return FederatedExperimentResult(            final_model=global_model,            best_balanced_model=best_balanced_model,            best_macro_f1_model=best_macro_f1_model,            history_df=history_df,            best_balanced_round=best_balanced_round,            best_macro_f1_round=best_macro_f1_round,            test_df=df_test,        )